-        Rcode.NXDOMAIN -> "Wide: NXDOMAIN"
-        else -> "Wide: ${Rcode.string(wideRcode)}"
-      }
-
-    return when {
-      localCount == 0 && wideRcode == null -> "Searching for bridges…"
-      localCount == 0 -> "$wide"
-      else -> "Local: $localCount • $wide"
